class TodoItemNotFoundError(Exception):
    """Raised when a todo item with the given ID is not found."""
    pass

class TodoStorageError(Exception):
    """Raised when a storage operation fails."""
    pass

from todo_app.exceptions import TodoItemNotFoundError, TodoStorageError

def test_TodoItemNotFoundError_is_exception(): assert issubclass(TodoItemNotFoundError, Exception)
def test_TodoStorageError_is_exception(): assert issubclass(TodoStorageError, Exception)
def test_TodoItemNotFoundError_can_raise(): raise TodoItemNotFoundError('test')
def test_TodoStorageError_can_raise(): raise TodoStorageError('test')

import tests

def test_tests_package_exists(): assert tests is not None
def test_tests_package_is_module(): import inspect; assert inspect.ismodule(tests)

from todo_app.main import add_todo, list_todos, complete_todo, remove_todo
from todo_app.exceptions import TodoItemNotFoundError

def test_add_todo_returns_int_id(): assert isinstance(add_todo('test'), int)
def test_complete_todo_raises_for_invalid_id(): raises TodoItemNotFoundError when complete_todo(999)
def test_remove_todo_decreases_list_length(): initial = len(list_todos()); remove_todo(valid_id); assert len(list_todos()) == initial - 1

